@@ -153,9 +153,12 @@ pub fn genFloat(self: *NativeCodegen, args: []ast.Node) CodegenError!void {
             // Strip leading + for Zig compatibility (Zig doesn't accept "+123")
             const parse_str = if (str_val.len > 0 and str_val[0] == '+') str_val[1..] else str_val;
             if (std.fmt.parseFloat(f64, parse_str)) |_| {
-                try self.emit("@as(f64, ");
-                try self.emit(parse_str);
-                try self.emit(")");
+                try self.emitCallCtx("@as", parse_str, struct {
+                    pub fn f(s: *NativeCodegen, p: []const u8) CodegenError!void {
+                        try s.emit("f64, ");
+                        try s.emit(p);
+                    }
+                }.f);
                 return;
             } else |_| {}
         }

@@ -20,17 +20,23 @@ pub fn genSubTest(self: *NativeCodegen, obj: ast.Node, args: []ast.Node, keyword
         // Check if value is an integer constant
         if (kw.value == .constant and kw.value.constant.value == .int) {
             // Pattern: subTest(i=0) -> subTestInt("i", 0)
-            try self.emit("runtime.unittest.subTestInt(\"");
-            try self.emit(kw.name);
-            try self.emit("\", ");
-            try parent.genExpr(self, kw.value);
-            try self.emit(")");
+            const Ctx = struct { name: []const u8, val: ast.Node };
+            try self.emitCallCtx("runtime.unittest.subTestInt", Ctx{ .name = kw.name, .val = kw.value }, struct {
+                pub fn f(s: *NativeCodegen, ctx: Ctx) CodegenError!void {
+                    try s.emit("\"");
+                    try s.emit(ctx.name);
+                    try s.emit("\", ");
+                    try parent.genExpr(s, ctx.val);
+                }
+            }.f);
             return;
         } else {
             // Pattern: subTest(msg="label") -> subTest("label")
-            try self.emit("runtime.unittest.subTest(");
-            try parent.genExpr(self, kw.value);
-            try self.emit(")");
+            try self.emitCallCtx("runtime.unittest.subTest", kw.value, struct {
+                pub fn f(s: *NativeCodegen, e: ast.Node) CodegenError!void {
+                    try parent.genExpr(s, e);
+                }
+            }.f);
             return;
         }
     }
